// Get input data
const items = $input.all();

// Initialize storage for unique set IDs
const seenSetIds = new Set();
const result = [];

// Iterate through sorted data
for (const item of items) {
    const setId = item.json["data.data.phase.sets.nodes[0].id"];

    if (!seenSetIds.has(setId)) {
        seenSetIds.add(setId);
        result.push(item);
    }
}

// Return filtered results
return result;

// Define max tournament name length
const maxLength = 40;

const hashtagKeywords = {
    "Rivals2": "#Rivals2",
    "Rivals of Aether": "#RivalsOfAether",
    "Melee": "#Melee",
    "Rivals": "#Rivals",
    "Smash": "#Smash",
    "Ultimate": "#Ultimate",
    "Aether": "#Aether"
};

const addHashtags = (name) => {
    let updatedName = name;
    Object.keys(hashtagKeywords).forEach((word) => {
        const regex = new RegExp(`\\b${word}\\b`, "gi");
        updatedName = updatedName.replace(regex, hashtagKeywords[word]);
    });
    return updatedName;
};

// Truncate base name only, then re-attach location so it's never dropped.
const truncateName = (baseName, location) => {
    const locationSuffix = location ? ` (${location})` : '';
    const maxBase = maxLength - locationSuffix.length;

    let truncated = addHashtags(baseName);
    if (truncated.length <= maxBase) return truncated + locationSuffix;

    const splitCharacters = ["-", "@", "#", ":", "|"];
    let segments = [truncated];
    splitCharacters.forEach((char) => {
        if (truncated.includes(char)) {
            segments = truncated.split(char).map(s => s.trim());
        }
    });

    let cleanedName = segments[0];
    for (let i = 1; i < segments.length; i++) {
        const segment = segments[i];
        if (Object.keys(hashtagKeywords).some(key => segment.includes(key))) {
            cleanedName += `, ${segment}`;
        }
    }

    if (cleanedName.length > maxBase) {
        cleanedName = cleanedName.substring(0, maxBase).trim();
        if (cleanedName.includes(" ")) {
            cleanedName = cleanedName.substring(0, cleanedName.lastIndexOf(" "));
        }
        cleanedName += "...";
    }

    return cleanedName + locationSuffix;
};

const characterIcons = {
    "Forsburn": "☠️",
    "Loxodont": "🐘",
    "Clairen": "🤺",
    "Zetterburn": "🦁",
    "Wrastor": "🦅",
    "Fleet": "🦊",
    "Maypul": "🌱",
    "Kragg": "🪲",
    "Ranno": "🐸",
    "Orcane": "🐋",
    "Etalus": "🐻",
    "Olympia": "💎",
    "La Reina": "🪑",
    "Absa": "⚡",
    "Galvan": "🧲",
    "Slade": "🦈"
};

const totalEntrants = $input.first().json.data[0]["sum_'data_data_tournaments_nodes'_events0_numEntrants"] || 0;

const tournamentData = Array.from({ length: 5 }, (_, i) => {
    const tournamentNode = $input.first()?.json?.data?.[i]?.["data.data.tournaments.nodes"] || {};
    const eventNode = $input.first()?.json?.data?.[i]?.["data.data.set.event"] || {};
    const winnerName = $input.first()?.json?.data?.[i]?.winnerName || "";

    const baseName = eventNode.tournament?.name || tournamentNode.name || "N/A";

    const location = tournamentNode.countryCode && tournamentNode.countryCode !== "US"
        ? tournamentNode.countryCode
        : tournamentNode.addrState || "";

    const entrants = $input.first()?.json?.data?.[i]?.["['data.data.tournaments.nodes'].events"]?.numEntrants || 0;

    const eventsNode = $input.first()?.json?.data?.[i]?.["['data.data.tournaments.nodes'].events"] || {};
    const eventSlug = eventsNode.slug || tournamentNode.events?.[0]?.slug || null;

    let charCounts = {};
    let gameIndex = 0;
    while (true) {
        const sel = $input.first()?.json?.data?.[i]?.["data.data.set.games[" + gameIndex + "].selections"];
        if (!sel) break;
        const entrantName = sel?.entrant?.name || "";
        if (entrantName === winnerName || entrantName.includes(winnerName.split(" ").pop())) {
            const c = sel?.character?.name;
            if (c) charCounts[c] = (charCounts[c] || 0) + 1;
        }
        gameIndex++;
    }
    const characterName = Object.entries(charCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
    const icon = characterIcons[characterName] || "W:";

    return {
        originalName: location ? `${baseName} (${location})` : baseName,
        truncatedName: truncateName(baseName, location),
        entrants,
        winner: winnerName ? `   ${icon} ${winnerName}` : "",
        eventSlug
    };
});

while (tournamentData.length < 5) {
    tournamentData.push({ originalName: "N/A", truncatedName: "N/A", entrants: 0, winner: "", eventSlug: null });
}

// Full result (all 5 tournaments) for character count reference
const inputString = "Yesterday in #Rivals2!";
let fullList = "\n\n";
tournamentData.forEach(t => {
    fullList += `${t.truncatedName} - ${t.entrants} entrants\n${t.winner}\n`;
});
const finalString = `${inputString}${fullList}\nEntrants yesterday: ${totalEntrants}`.trim();

// Main post: first 3 tournaments (split 3/2)
let mainList = "\n\n";
tournamentData.slice(0, 3).forEach(t => {
    mainList += `${t.truncatedName} - ${t.entrants} entrants\n${t.winner}\n`;
});
const mainPostText = `${inputString}${mainList}\nEntrants yesterday: ${totalEntrants}`;

// Reply: remaining tournaments
let replyList = "";
tournamentData.slice(3).filter(t => t.truncatedName !== 'N/A').forEach(t => {
    replyList += `${t.truncatedName} - ${t.entrants} entrants\n${t.winner}\n`;
});
const replyText = replyList.trim();

return [{ 
    result: finalString, 
    characterCount: finalString.length,
    mainPostText,
    replyText,
    tournamentLinks: tournamentData
        .filter(t => t.eventSlug && t.truncatedName !== 'N/A')
        .map(t => ({
            text: t.truncatedName,
            url: `https://www.start.gg/${t.eventSlug}`
        }))
}];

parameters.query:
=query SetInfo($setId: ID!) {
    set(id: $setId) {
        id
        winnerId
        games {
            selections {
                character {
                    name
                }
                entrant {
                    name
                    id
                }
            }
        }
        displayScore
        event {
            tournament {
                name
            }
            id
        }
    }
}

