for (const item of items) {

    // Extract the event ID (used for uniqueness filtering)
    const eventId = item.json["data.data.event.id"];

    // If this event ID hasn't been seen before, add it to the result list
    if (!seenEventIds.has(eventId)) {
        seenEventIds.add(eventId); // Mark it as seen
        result.push(item); // Store the first occurrence of this event ID
    }

    // Stop processing once we have collected 5 unique events
    if (result.length === 5) {
        break;  
    }
}

// Return the filtered results containing at most 5 unique event IDs
return result;

// Build facets for rich text (AT Protocol)
// Link facets take priority; hashtag facets skip positions that overlap a link span
function buildFacets(text, links) {
  const facets = [];

  // 1. Link facets for tournament names
  for (const { text: linkText, url } of links) {
    let idx = text.indexOf(linkText);
    let matchedText = linkText;
    if (idx === -1) {
      matchedText = linkText.replace(/#([a-zA-Z])/g, '$1');
      idx = text.indexOf(matchedText);
    }
    if (idx === -1) continue;
    const byteStart = Buffer.byteLength(text.substring(0, idx), 'utf8');
    const byteEnd   = byteStart + Buffer.byteLength(matchedText, 'utf8');
    facets.push({
      index: { byteStart, byteEnd },
      features: [{ $type: 'app.bsky.richtext.facet#link', uri: url }]
    });
  }

  // 2. Hashtag facets — skip any that overlap a link facet
  const regex = /#[a-zA-Z][a-zA-Z0-9_]*/g;
  let match;
  while ((match = regex.exec(text)) !== null) {
    const byteStart = Buffer.byteLength(text.substring(0, match.index), 'utf8');
    const byteEnd   = byteStart + Buffer.byteLength(match[0], 'utf8');
    const overlaps  = facets.some(f => byteStart < f.index.byteEnd && byteEnd > f.index.byteStart);
    if (!overlaps) {
      facets.push({
        index: { byteStart, byteEnd },
        features: [{ $type: 'app.bsky.richtext.facet#tag', tag: match[0].slice(1) }]
      });
    }
  }

  return facets;
}

