const futureDate = new Date(Date.now() + 1000);

const replyPostData = {
    repo: $('Set Bluesky Credentials').first().json.BlueskyHandle,
    collection: "app.bsky.feed.post",
    record: {
        "$type": "app.bsky.feed.post",
        text: replyText,
        reply: {
            root: {
                cid: $('Create Initial Post').first().json.cid,
                uri: $('Create Initial Post').first().json.uri
            },
            parent: {
                cid: $('Create Initial Post').first().json.cid,
                uri: $('Create Initial Post').first().json.uri
            }
        },
        ...(facets.length > 0 && { facets }),
        createdAt: futureDate.toISOString()
    }
};

return replyPostData;

// Grand Finals = highest positive round (winners side always positive in double-elim)
// If multiple sets at that round (GF + reset), pick the latest completedAt
return $input.all().map(item => {
  const sets = item.json.data?.data?.phase?.sets?.nodes || [];
  if (sets.length === 0) return item;

  // Only look at positive rounds (winners/GF side)
  const winnersSets = sets.filter(s => s.round > 0);
  if (winnersSets.length === 0) return item;

  // Highest positive round = Grand Finals round
  const maxRound = Math.max(...winnersSets.map(s => s.round));

  // Among GF-round sets, pick latest completedAt (handles bracket reset)
  const gfSets = winnersSets.filter(s => s.round === maxRound);
  const trueGF = gfSets.reduce((latest, s) =>
    s.completedAt > latest.completedAt ? s : latest
  );

  const out = JSON.parse(JSON.stringify(item.json));
  out.data.data.phase.sets.nodes = [trueGF];
  return { json: out };
});

function stripSponsor(winnerLine) {
  // Strips 'Sponsor | ' prefix: '   🦁 The Strong One | HamPolo' => '   🦁 HamPolo'
  return winnerLine.replace(/^(   \S+\s).*\|\s*(.+)$/, '$1$2');
}

function truncateIfNeeded(text) {
  if (text.length <= 300) return text;
  return text.split('\n').map(line =>
    line.includes(' | ') ? stripSponsor(line) : line
  ).join('\n');
}

const data = $input.first().json;
return [{
  ...data,
  mainPostText: truncateIfNeeded(data.mainPostText),
  replyText:    truncateIfNeeded(data.replyText)
}];
